// ========================================
// WF1 v10 - EXTRACT & RATE LIMIT
// Max 2 emails per clarification per day
// ========================================

const input = $input.first().json;
const results = input.results || [];

console.log('[WF1 v10] ==========================================');
console.log('[WF1 v10] Total clarifications found:', results.length);

if (results.length === 0) {
  console.log('[WF1 v10] No clarifications to process');
  return { json: { hasItems: false, items: [], skipped: 0, toProcess: 0 } };
}

const now = new Date();
const today = now.toISOString().split('T')[0];
const items = [];
let skippedCount = 0;

for (const page of results) {
  const props = page.properties;
  const id = page.id;

  // Extract basic info
  const title = props['Tiêu đề']?.title?.[0]?.plain_text || 'Untitled';
  const status = props['Tình trạng']?.select?.name || '';
  const nguon = props['Nguồn']?.select?.name || 'CEO';
  const noiDungGoc = props['Nội dung gốc']?.rich_text?.[0]?.plain_text || '';
  const ngayNhan = props['Ngày nhận']?.date?.start || '';

  // Email info
  const emailDauMoi = props['📧 Email đầu mối']?.email || '';

  // Rate limiting fields
  const soLanGui = props['📧 Số lần gửi']?.number || 0;
  const ngayGuiGanNhat = props['📅 Ngày gửi gần nhất']?.date?.start || '';

  // T1 from HR relation
  const hrRelation = props['👤 Người nhận chỉ đạo']?.relation || [];

  console.log('[WF1 v10] Processing:', title.substring(0, 40));
  console.log('  Status:', status);
  console.log('  Số lần gửi:', soLanGui);
  console.log('  Ngày gửi gần nhất:', ngayGuiGanNhat);

  // ==========================================
  // RATE LIMIT CHECK
  // ==========================================

  let shouldSkip = false;
  let skipReason = '';

  // Check 1: Đã gửi >= 2 lần hôm nay?
  if (ngayGuiGanNhat === today && soLanGui >= 2) {
    shouldSkip = true;
    skipReason = 'Đã gửi ' + soLanGui + ' lần hôm nay (max 2)';
  }

  // Check 2: Đã gửi hôm nay và là lần thứ 2?
  // Nếu ngày gửi gần nhất là hôm nay và đã gửi 1 lần, cho phép gửi thêm 1 lần nữa
  // Nếu ngày gửi khác hôm nay, reset counter

  if (shouldSkip) {
    console.log('  ⏭️ SKIPPED:', skipReason);
    skippedCount++;
    continue;
  }

  // ==========================================
  // PREPARE ITEM FOR PROCESSING
  // ==========================================

  items.push({
    clarificationId: id,
    title,
    status,
    nguon,
    noiDungGoc,
    ngayNhan,
    emailDauMoi,
    hrRelationIds: hrRelation.map(r => r.id),

    // Rate limit tracking
    soLanGuiHienTai: soLanGui,
    ngayGuiGanNhat,
    soLanGuiMoi: ngayGuiGanNhat === today ? soLanGui + 1 : 1,

    // Computed
    isNewToday: ngayGuiGanNhat !== today,
    today
  });

  console.log('  ✅ Added to process queue');
}

console.log('[WF1 v10] ==========================================');
console.log('[WF1 v10] Summary:');
console.log('  Total found:', results.length);
console.log('  Skipped (rate limit):', skippedCount);
console.log('  To process:', items.length);

return {
  json: {
    hasItems: items.length > 0,
    items,
    skipped: skippedCount,
    toProcess: items.length,
    timestamp: now.toISOString()
  }
};

// ========================================
// RESOLVE EMAIL - Dynamic lookup
// ========================================

const item = $input.first().json;

console.log('[WF1 v10] Resolving email for:', item.title?.substring(0, 40));

// Priority: emailDauMoi > HR lookup > fallback
let recipientEmail = item.emailDauMoi || '';
let emailSource = 'direct';

if (!recipientEmail && item.hrRelationIds?.length > 0) {
  // Would need HR lookup here - for now use fallback
  emailSource = 'hr_lookup_needed';
}

if (!recipientEmail) {
  recipientEmail = 'vynnl@esuhai.com';
  emailSource = 'fallback';
}

console.log('  Email:', recipientEmail, '(' + emailSource + ')');

// Build prefill URL
const baseUrl = 'https://docs.google.com/forms/d/e/1FAIpQLSdzRTOucM4qWwlxyx3yEelDorBv2ADnL8jFUUW7-xpqdidvBw/viewform';
const params = new URLSearchParams();

// Form entry IDs
params.append('entry.1684171280', item.clarificationId || '');
params.append('entry.1878008034', item.nguon || '');
params.append('entry.1953342780', item.ngayNhan || '');
params.append('entry.1839616630', item.noiDungGoc || '');
params.append('entry.649583359', item.title?.split(':')[0]?.trim() || '');

const prefillUrl = baseUrl + '?' + params.toString();

return {
  json: {
    ...item,
    recipientEmail,
    emailSource,
    prefillUrl,
    ccEmail: 'hoangkha@esuhai.com'
  }
};

